mapper.select:
SELECT r.code
FROM organization_user_roles our
         JOIN roles r ON r.id = our.role_id
WHERE our.org_id = #{orgId}
  AND our.user_id = #{userId}

WITH RECURSIVE role_tree AS ( -- 锚点：用户在该组织下直接拥有的角色 SELECT r.id, r.parent_role_id FROM organization_user_roles our JOIN roles r ON r.id = our.role_id WHERE our.org_id = #{orgId} AND our.user_id = #{userId}
UNION
-- 递归：沿 parent_role_id 向上 SELECT p.id, p.parent_role_id FROM roles p JOIN role_tree rt ON rt.parent_role_id = p.id ) SELECT DISTINCT id FROM role_tree
